import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import VideoUpload from '../../components/VideoUpload/VideoUpload';
import OTPVerification from '../../components/OTPVerification/OTPVerification';
import './Askuestion.css';

const AskQuestion = () => {
  const [videoFile, setVideoFile] = useState(null);
  const [showOTPVerification, setShowOTPVerification] = useState(false);
  const [isVerified, setIsVerified] = useState(false);
  const navigate = useNavigate();

  const handleVideoSelect = async (file) => {
    setVideoFile(file);
    setShowOTPVerification(true);
  };

  const handleVerificationComplete = () => {
    setIsVerified(true);
    setShowOTPVerification(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!isVerified || !videoFile) return;

    const formData = new FormData();
    formData.append('video', videoFile);
    // Add other question details to formData

    try {
      await axios.post('/api/questions/ask-video', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      navigate('/'); // Redirect to home page after successful upload
    } catch (error) {
      console.error('Error uploading video question:', error);
    }
  };

  return (
    <div className="ask-question">
      <h1>Ask a Video Question</h1>
      {showOTPVerification ? (
        <OTPVerification
          email={user.email}
          onVerificationComplete={handleVerificationComplete}
        />
      ) : (
        <form onSubmit={handleSubmit}>
          {/* Existing question form fields */}
          <VideoUpload onVideoSelect={handleVideoSelect} />
          <button 
            type="submit" 
            disabled={!isVerified || !videoFile}
            className="review-btn"
          >
            Post Your Question
          </button>
        </form>
      )}
    </div>
  );
};

export default AskQuestion;
